import { useEffect, useState } from 'react';
import { getApiUrl } from '../hooks/useElectron';
import useElectron from '../hooks/useElectron';

const API_URL = getApiUrl();

function getAuthHeaders() {
  const token = localStorage.getItem('capra_token');
  return token ? { Authorization: `Bearer ${token}` } : {};
}

/**
 * Cloud Architecture Diagram Component
 * Displays PNG diagrams generated by the Python diagrams library
 */
function CloudArchitectureDiagram({
  imageUrl,
  expanded = false,
  loading = false,
  error = null,
  cloudProvider = 'auto'
}) {
  const [imageError, setImageError] = useState(false);

  // Reset image error when URL changes
  useEffect(() => {
    if (imageUrl) {
      setImageError(false);
    }
  }, [imageUrl]);

  if (loading) {
    return (
      <div className={`p-6 rounded-lg bg-white border border-gray-200 text-center ${expanded ? 'min-h-[400px]' : ''}`}>
        <div className="flex flex-col items-center justify-center gap-3">
          <svg className="w-8 h-8 animate-spin text-emerald-500" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
          </svg>
          <div>
            <p className="text-sm text-gray-600 font-medium">Generating architecture diagram...</p>
            <p className="text-xs text-gray-400 mt-1">Using {cloudProvider.toUpperCase()} cloud icons</p>
          </div>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="p-4 rounded-lg bg-red-50 border border-red-200">
        <p className="text-sm text-red-600">{error}</p>
      </div>
    );
  }

  if (!imageUrl || imageError) {
    console.log('[CloudDiagram] Showing placeholder:', { imageUrl, imageError });
    return (
      <div className="text-center py-6 text-gray-400">
        <svg className="w-12 h-12 mx-auto mb-3 text-gray-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M3 15a4 4 0 004 4h9a5 5 0 10-.1-9.999 5.002 5.002 0 10-9.78 2.096A4.001 4.001 0 003 15z" />
        </svg>
        <p className="text-xs">Click Generate for cloud architecture diagram</p>
        <p className="text-[10px] text-gray-300 mt-1">Real AWS/GCP/Azure icons</p>
        {imageError && <p className="text-[10px] text-red-400 mt-1">Image failed to load</p>}
      </div>
    );
  }

  console.log('[CloudDiagram] Showing image:', imageUrl);

  return (
    <div className={`rounded-lg overflow-hidden border border-gray-200 bg-white ${expanded ? 'p-4' : ''}`}>
      <img
        src={imageUrl}
        alt="Cloud Architecture Diagram"
        className={`w-full h-auto object-contain ${expanded ? 'max-h-[70vh]' : 'max-h-[250px]'}`}
        onError={(e) => {
          console.error('[CloudDiagram] Image load error:', imageUrl, e);
          setImageError(true);
        }}
        onLoad={() => console.log('[CloudDiagram] Image loaded successfully:', imageUrl)}
      />
    </div>
  );
}

// Modal component for full-screen diagram view
function DiagramModal({ isOpen, onClose, title, children }) {
  if (!isOpen) return null;

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center bg-black/50"
      onClick={onClose}
    >
      <div
        className="relative bg-white rounded-lg shadow-xl w-[95vw] h-[90vh] flex flex-col border border-gray-200"
        onClick={e => e.stopPropagation()}
      >
        {/* Header */}
        <div className="flex items-center justify-between px-4 py-3 border-b border-gray-200 bg-gray-50">
          <h3 className="text-sm font-semibold text-gray-800 uppercase tracking-wide">
            {title}
          </h3>
          <button
            onClick={onClose}
            className="p-1.5 rounded-lg hover:bg-gray-200 transition-colors"
          >
            <svg className="w-5 h-5 text-gray-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>
        {/* Content */}
        <div className="flex-1 overflow-auto p-4 flex items-center justify-center bg-white">
          {children}
        </div>
      </div>
    </div>
  );
}

// Collapsible section component
function CollapsibleSection({ title, icon, color, children, defaultOpen = true, badge }) {
  const [isOpen, setIsOpen] = useState(defaultOpen);

  return (
    <div className="rounded-lg bg-white border border-gray-200 overflow-hidden">
      <button
        onClick={() => setIsOpen(!isOpen)}
        className="w-full px-3 py-2 flex items-center justify-between hover:bg-gray-50 transition-colors"
      >
        <span className="text-[11px] font-semibold text-gray-700 uppercase tracking-wide flex items-center gap-2">
          {title}
          {badge && <span className="px-1.5 py-0.5 bg-emerald-50 text-emerald-600 border border-emerald-200 rounded text-[9px] font-medium">{badge}</span>}
        </span>
        <svg
          className={`w-3.5 h-3.5 text-gray-400 transition-transform ${isOpen ? 'rotate-180' : ''}`}
          fill="none"
          stroke="currentColor"
          viewBox="0 0 24 24"
        >
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
        </svg>
      </button>
      {isOpen && <div className="px-3 pb-3 pt-1">{children}</div>}
    </div>
  );
}

export default function SystemDesignPanel({ systemDesign, eraserDiagram, onGenerateEraserDiagram, question, cloudProvider = 'auto' }) {
  const { isElectron } = useElectron();
  const [generatingEraser, setGeneratingEraser] = useState(false);
  const [diagramModal, setDiagramModal] = useState(false);
  const [proDiagramModal, setProDiagramModal] = useState(false);
  const [imageError, setImageError] = useState(false);

  // Cloud diagram state (desktop only - requires Python + graphviz)
  const [generatingDiagram, setGeneratingDiagram] = useState(false);
  const [diagramData, setDiagramData] = useState(null);
  const [diagramError, setDiagramError] = useState(null);

  // Check if this is a comparison question
  const hasComparison = systemDesign?.comparison || systemDesign?.comparisonDiagram;

  // Reset image error when new diagram is generated
  useEffect(() => {
    if (eraserDiagram?.imageUrl) {
      setImageError(false);
    }
  }, [eraserDiagram?.imageUrl]);

  // Auto-generate cloud diagram when systemDesign is available (desktop only)
  // Auto-generate diagram when system design is included
  useEffect(() => {
    if (systemDesign?.included && question && !diagramData && !generatingDiagram && !diagramError) {
      // Small delay to ensure component is fully mounted and auth is ready
      const timer = setTimeout(() => {
        handleGenerateDiagram();
      }, 500);
      return () => clearTimeout(timer);
    }
  }, [systemDesign?.included, question]);

  const handleGenerateEraser = async () => {
    if (!onGenerateEraserDiagram) return;
    setGeneratingEraser(true);
    try {
      await onGenerateEraserDiagram();
    } finally {
      setGeneratingEraser(false);
    }
  };

  const handleGenerateDiagram = async () => {
    if (!question) return;

    setGeneratingDiagram(true);
    setDiagramError(null);

    try {
      const response = await fetch(`${API_URL}/api/diagram/generate`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          ...getAuthHeaders(),
        },
        body: JSON.stringify({
          question,
          cloudProvider: cloudProvider || 'auto',
          difficulty: 'medium',
          category: 'System Design',
          format: 'png'
        }),
      });

      if (!response.ok) {
        // Try to parse error as JSON, fallback to status text
        let errorMessage = `Failed to generate diagram (${response.status})`;
        try {
          const errorData = await response.json();
          errorMessage = errorData.error || errorMessage;
        } catch {
          // Response wasn't JSON (might be HTML error page)
          errorMessage = `Server error: ${response.status} ${response.statusText}`;
        }
        throw new Error(errorMessage);
      }

      const result = await response.json();

      if (result.success && result.image_url) {
        setDiagramData({
          imageUrl: `${API_URL}${result.image_url}`,
          cloudProvider: result.cloud_provider,
          pythonCode: result.python_code
        });
      } else {
        throw new Error(result.error || 'Diagram generation failed');
      }
    } catch (error) {
      console.error('[Diagram] Generation error:', error);
      setDiagramError(error.message);
    } finally {
      setGeneratingDiagram(false);
    }
  };

  if (!systemDesign || !systemDesign.included) {
    return null;
  }

  return (
    <div className="p-3 rounded-lg animate-fade-in bg-white border border-gray-200">
      {/* Header */}
      <div className="mb-3 pb-2 border-b border-gray-100 flex items-center justify-between">
        <span className="text-xs font-bold uppercase tracking-wider text-gray-800">System Design</span>
      </div>

      <div className="space-y-3">
        {/* Row 1: Overview - Full width */}
        {systemDesign.overview && (
          <div className="rounded-lg p-3 bg-gray-50 border border-gray-200">
            <h4 className="text-[11px] font-semibold text-gray-700 uppercase tracking-wide mb-1.5">
              Overview
            </h4>
            <p className="text-[12px] text-gray-600 leading-relaxed">{systemDesign.overview}</p>
          </div>
        )}

        {/* Row 2: Requirements - Functional & Non-Functional side by side */}
        {systemDesign.requirements && (
          <div className="grid grid-cols-2 gap-3">
            {/* Functional Requirements */}
            {systemDesign.requirements.functional && systemDesign.requirements.functional.length > 0 && (
              <div className="rounded-lg p-3 bg-gray-50 border border-gray-200">
                <h4 className="text-[11px] font-semibold text-gray-700 uppercase tracking-wide mb-2">
                  Functional
                </h4>
                <ul className="space-y-1">
                  {systemDesign.requirements.functional.map((req, i) => (
                    <li key={i} className="text-[11px] text-gray-600 flex items-start gap-2">
                      <span className="text-emerald-500 mt-0.5 flex-shrink-0">•</span>
                      {req}
                    </li>
                  ))}
                </ul>
              </div>
            )}
            {/* Non-Functional Requirements */}
            {systemDesign.requirements.nonFunctional && systemDesign.requirements.nonFunctional.length > 0 && (
              <div className="rounded-lg p-3 bg-gray-50 border border-gray-200">
                <h4 className="text-[11px] font-semibold text-gray-700 uppercase tracking-wide mb-2">
                  Non-Functional
                </h4>
                <ul className="space-y-1">
                  {systemDesign.requirements.nonFunctional.map((req, i) => (
                    <li key={i} className="text-[11px] text-gray-600 flex items-start gap-2">
                      <span className="text-emerald-500 mt-0.5 flex-shrink-0">•</span>
                      {req}
                    </li>
                  ))}
                </ul>
              </div>
            )}
          </div>
        )}

        {/* Row 2: Architecture Components + Scalability side by side */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-3">
          {/* Architecture Components */}
          {systemDesign.architecture && (
            <div className="rounded-lg p-3 bg-gray-50 border border-gray-200">
              <h4 className="text-[11px] font-semibold text-gray-700 uppercase tracking-wide mb-2">
                Components
              </h4>
              {systemDesign.architecture.components && systemDesign.architecture.components.length > 0 && (
                <div className="flex flex-wrap gap-1.5 mb-2">
                  {systemDesign.architecture.components.map((component, i) => (
                    <span
                      key={i}
                      className="px-2 py-0.5 bg-white text-gray-700 text-[10px] rounded border border-gray-300"
                    >
                      {component}
                    </span>
                  ))}
                </div>
              )}
              {systemDesign.architecture.description && (
                <p className="text-[11px] text-gray-600 leading-relaxed">{systemDesign.architecture.description}</p>
              )}
            </div>
          )}

          {/* Scalability - Compact badges */}
          {systemDesign.scalability && systemDesign.scalability.length > 0 && (
            <div className="rounded-lg p-3 bg-gray-50 border border-gray-200">
              <h4 className="text-[11px] font-semibold text-gray-700 uppercase tracking-wide mb-2">
                Scalability
              </h4>
              <div className="flex flex-wrap gap-1.5">
                {systemDesign.scalability.map((item, i) => (
                  <span
                    key={i}
                    className="inline-flex items-center gap-1.5 px-2 py-0.5 bg-emerald-50 text-emerald-700 text-[10px] rounded border border-emerald-200"
                    title={item}
                  >
                    <svg className="w-3 h-3 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" />
                    </svg>
                    {item.length > 30 ? item.slice(0, 30) + '...' : item}
                  </span>
                ))}
              </div>
            </div>
          )}
        </div>

        {/* Row 3: API Design - Collapsible */}
        {systemDesign.apiDesign && systemDesign.apiDesign.length > 0 && (
          <CollapsibleSection
            title="API Design"
            defaultOpen={false}
            badge={`${systemDesign.apiDesign.length}`}
          >
            <div className="grid grid-cols-1 md:grid-cols-2 gap-2">
              {systemDesign.apiDesign.map((api, i) => (
                <div key={i} className="bg-white border border-gray-200 rounded-lg p-2.5">
                  <div className="flex flex-wrap items-center gap-2 mb-1.5">
                    <span className={`px-1.5 py-0.5 text-[10px] font-mono font-semibold rounded ${
                      api.method === 'GET' ? 'bg-emerald-50 text-emerald-600 border border-emerald-200' :
                      api.method === 'POST' ? 'bg-gray-100 text-gray-700 border border-gray-300' :
                      api.method === 'PUT' ? 'bg-gray-100 text-gray-700 border border-gray-300' :
                      api.method === 'DELETE' ? 'bg-gray-100 text-gray-500 border border-gray-300' :
                      'bg-gray-100 text-gray-600 border border-gray-200'
                    }`}>
                      {api.method}
                    </span>
                    <code className="text-[11px] font-mono text-gray-700 break-all">{api.endpoint}</code>
                  </div>
                  <p className="text-[11px] text-gray-500">{api.description}</p>
                </div>
              ))}
            </div>
          </CollapsibleSection>
        )}

        {/* Row 4: Data Model - Collapsible */}
        {systemDesign.dataModel && systemDesign.dataModel.length > 0 && (
          <CollapsibleSection
            title="Data Model"
            defaultOpen={false}
            badge={`${systemDesign.dataModel.length} tables`}
          >
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-2">
              {systemDesign.dataModel.map((table, i) => (
                <div key={i} className="bg-white border border-gray-200 rounded-lg overflow-hidden">
                  <div className="px-2.5 py-1.5 bg-gray-50 border-b border-gray-200">
                    <span className="text-[10px] font-semibold text-gray-700 font-mono">{table.table}</span>
                  </div>
                  <div className="p-2 max-h-28 overflow-y-auto">
                    {table.fields && table.fields.map((field, j) => (
                      <div key={j} className="flex items-center gap-2 text-[10px] py-0.5">
                        <span className="font-mono text-gray-700">{field.name}</span>
                        <span className="font-mono text-gray-400">{field.type}</span>
                      </div>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </CollapsibleSection>
        )}

        {/* Row 5: Tech Justifications - Compact grid layout */}
        {systemDesign.techJustifications && systemDesign.techJustifications.length > 0 && (
          <CollapsibleSection
            title="Why These Technologies?"
            defaultOpen={true}
            badge={`${systemDesign.techJustifications.length}`}
          >
            <div className="grid grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-3">
              {systemDesign.techJustifications.map((item, i) => (
                <div key={i} className="bg-white border border-gray-200 rounded-lg p-3 hover:border-emerald-300 transition-colors">
                  {/* Tech name + category header */}
                  <div className="flex flex-wrap items-center gap-1.5 mb-2">
                    <span className="px-1.5 py-0.5 bg-emerald-600 text-white text-[10px] font-semibold rounded">
                      {item.tech}
                    </span>
                    {item.category && (
                      <span className="px-1.5 py-0.5 bg-gray-100 text-gray-600 text-[9px] font-medium rounded">
                        {item.category}
                      </span>
                    )}
                  </div>
                  {/* Why - main content - full text */}
                  <p className="text-[11px] text-gray-600 leading-relaxed mb-2">
                    {item.why}
                  </p>
                  {/* Without & Alternatives - full text */}
                  <div className="space-y-1 text-[10px]">
                    {item.without && (
                      <p className="text-gray-500">
                        <span className="font-semibold text-gray-600">Risk:</span> {item.without}
                      </p>
                    )}
                    {item.alternatives && (
                      <p className="text-emerald-600">
                        <span className="font-semibold">Alt:</span> {item.alternatives}
                      </p>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </CollapsibleSection>
        )}

        {/* Comparison Section - for vs/compare questions */}
        {systemDesign.comparison && (
          <CollapsibleSection
            title="Comparison"
            defaultOpen={true}
          >
            <div className="grid grid-cols-2 gap-3">
              {/* Approach 1 */}
              {systemDesign.comparison.approach1 && (
                <div className="rounded-lg p-3 bg-white border border-gray-200">
                  <h5 className="text-[11px] font-bold text-gray-800 mb-2 flex items-center gap-2">
                    <span className="w-2 h-2 rounded-full bg-blue-500"></span>
                    {systemDesign.comparison.approach1.name || 'Approach 1'}
                  </h5>
                  {systemDesign.comparison.approach1.pros && (
                    <div className="mb-2">
                      <span className="text-[9px] font-semibold text-emerald-600 uppercase">Pros</span>
                      <ul className="mt-1 space-y-0.5">
                        {systemDesign.comparison.approach1.pros.map((pro, i) => (
                          <li key={i} className="text-[10px] text-gray-600 flex items-start gap-1.5">
                            <span className="text-emerald-500 mt-0.5">+</span>
                            {pro}
                          </li>
                        ))}
                      </ul>
                    </div>
                  )}
                  {systemDesign.comparison.approach1.cons && (
                    <div>
                      <span className="text-[9px] font-semibold text-red-600 uppercase">Cons</span>
                      <ul className="mt-1 space-y-0.5">
                        {systemDesign.comparison.approach1.cons.map((con, i) => (
                          <li key={i} className="text-[10px] text-gray-600 flex items-start gap-1.5">
                            <span className="text-red-500 mt-0.5">-</span>
                            {con}
                          </li>
                        ))}
                      </ul>
                    </div>
                  )}
                </div>
              )}
              {/* Approach 2 */}
              {systemDesign.comparison.approach2 && (
                <div className="rounded-lg p-3 bg-white border border-gray-200">
                  <h5 className="text-[11px] font-bold text-gray-800 mb-2 flex items-center gap-2">
                    <span className="w-2 h-2 rounded-full bg-purple-500"></span>
                    {systemDesign.comparison.approach2.name || 'Approach 2'}
                  </h5>
                  {systemDesign.comparison.approach2.pros && (
                    <div className="mb-2">
                      <span className="text-[9px] font-semibold text-emerald-600 uppercase">Pros</span>
                      <ul className="mt-1 space-y-0.5">
                        {systemDesign.comparison.approach2.pros.map((pro, i) => (
                          <li key={i} className="text-[10px] text-gray-600 flex items-start gap-1.5">
                            <span className="text-emerald-500 mt-0.5">+</span>
                            {pro}
                          </li>
                        ))}
                      </ul>
                    </div>
                  )}
                  {systemDesign.comparison.approach2.cons && (
                    <div>
                      <span className="text-[9px] font-semibold text-red-600 uppercase">Cons</span>
                      <ul className="mt-1 space-y-0.5">
                        {systemDesign.comparison.approach2.cons.map((con, i) => (
                          <li key={i} className="text-[10px] text-gray-600 flex items-start gap-1.5">
                            <span className="text-red-500 mt-0.5">-</span>
                            {con}
                          </li>
                        ))}
                      </ul>
                    </div>
                  )}
                </div>
              )}
            </div>
          </CollapsibleSection>
        )}

        {/* Row 6: Diagrams - Full width */}
        <div className="space-y-3">
          {/* Cloud Architecture Diagram (Python diagrams with real cloud icons) */}
          <div
            className={`rounded-lg p-3 bg-gray-50 border border-gray-200 ${diagramData ? 'cursor-pointer hover:border-emerald-300 group' : ''} transition-all`}
            onClick={() => diagramData && setDiagramModal(true)}
          >
            <h4 className="text-[11px] font-semibold text-gray-700 uppercase tracking-wide mb-2 flex items-center justify-between">
              <span className="flex items-center gap-1.5">
                Architecture Diagram
                {diagramData?.cloudProvider && (
                  <span className="px-1.5 py-0.5 bg-emerald-50 text-emerald-600 border border-emerald-200 rounded text-[9px] font-medium uppercase">
                    {diagramData.cloudProvider}
                  </span>
                )}
              </span>
              <div className="flex items-center gap-2">
                {diagramData && (
                  <span className="text-[9px] text-gray-400 group-hover:text-emerald-500 flex items-center gap-1">
                    <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 0l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5l-5-5m5 5v-4m0 4h-4" />
                    </svg>
                    Expand
                  </span>
                )}
                {!diagramData && !generatingDiagram && (
                  <button
                    onClick={(e) => { e.stopPropagation(); handleGenerateDiagram(); }}
                    className="flex items-center gap-1.5 px-2.5 py-1 text-[10px] font-medium rounded border transition-all bg-emerald-500 text-white border-emerald-500 hover:bg-emerald-600"
                  >
                    <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 15a4 4 0 004 4h9a5 5 0 10-.1-9.999 5.002 5.002 0 10-9.78 2.096A4.001 4.001 0 003 15z" />
                    </svg>
                    Generate
                  </button>
                )}
              </div>
            </h4>
            <div className="w-full">
              <CloudArchitectureDiagram
                imageUrl={diagramData?.imageUrl}
                loading={generatingDiagram}
                error={diagramError}
                cloudProvider={diagramData?.cloudProvider || cloudProvider}
              />
            </div>
          </div>

          {/* Professional Diagram (Eraser.io) - Full width, clickable when has diagram */}
          <div
            className={`rounded-lg p-3 bg-gray-50 border border-gray-200 ${eraserDiagram ? 'cursor-pointer hover:border-emerald-300 group' : ''} transition-all`}
            onClick={() => eraserDiagram && setProDiagramModal(true)}
          >
            <h4 className="text-[11px] font-semibold text-gray-700 uppercase tracking-wide mb-2 flex items-center justify-between">
              <span>Pro Diagram</span>
              <div className="flex items-center gap-2">
                {eraserDiagram && (
                  <span className="text-[9px] text-gray-400 group-hover:text-emerald-500 flex items-center gap-1">
                    <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 0l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5l-5-5m5 5v-4m0 4h-4" />
                    </svg>
                    Expand
                  </span>
                )}
                {onGenerateEraserDiagram && !eraserDiagram && (
                  <button
                    onClick={(e) => { e.stopPropagation(); handleGenerateEraser(); }}
                    disabled={generatingEraser}
                    className="flex items-center gap-1.5 px-2.5 py-1 text-[10px] font-medium rounded border transition-all"
                    style={{
                      background: generatingEraser ? '#f3f4f6' : '#10b981',
                      color: generatingEraser ? '#9ca3af' : 'white',
                      border: generatingEraser ? '1px solid #e5e7eb' : '1px solid #10b981',
                    }}
                  >
                    {generatingEraser ? (
                      <>
                        <svg className="w-3 h-3 animate-spin" fill="none" viewBox="0 0 24 24">
                          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
                        </svg>
                        Generating...
                      </>
                    ) : (
                      <>
                        <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 17V7m0 10a2 2 0 01-2 2H5a2 2 0 01-2-2V7a2 2 0 012-2h2a2 2 0 012 2m0 10a2 2 0 002 2h2a2 2 0 002-2M9 7a2 2 0 012-2h2a2 2 0 012 2m0 10V7m0 10a2 2 0 002 2h2a2 2 0 002-2V7a2 2 0 00-2-2h-2a2 2 0 00-2 2" />
                        </svg>
                        Generate
                      </>
                    )}
                  </button>
                )}
              </div>
            </h4>

            {eraserDiagram ? (
              <div className="w-full">
                {imageError ? (
                  <div className="rounded-lg border border-gray-200 bg-white p-4">
                    <p className="text-[11px] text-gray-600 mb-2">Failed to load diagram image</p>
                    <p className="text-[10px] text-gray-400 mb-2 break-all">URL: {eraserDiagram.imageUrl?.substring(0, 100)}...</p>
                    {eraserDiagram.editUrl && (
                      <a
                        href={eraserDiagram.editUrl}
                        target="_blank"
                        rel="noopener noreferrer"
                        onClick={(e) => e.stopPropagation()}
                        className="inline-flex items-center gap-1.5 px-2.5 py-1 text-[10px] font-medium rounded bg-gray-100 text-gray-700 border border-gray-200 hover:bg-gray-200"
                      >
                        View on Eraser.io
                      </a>
                    )}
                  </div>
                ) : (
                  <div className="rounded-lg overflow-hidden border border-gray-200 bg-white">
                    <img
                      src={eraserDiagram.imageUrl}
                      alt="Architecture Diagram"
                      className="w-full h-auto"
                      onError={(e) => {
                        console.error('Eraser image failed to load:', eraserDiagram.imageUrl);
                        setImageError(true);
                      }}
                    />
                  </div>
                )}
                {!imageError && eraserDiagram.editUrl && (
                  <a
                    href={eraserDiagram.editUrl}
                    target="_blank"
                    rel="noopener noreferrer"
                    onClick={(e) => e.stopPropagation()}
                    className="mt-2 inline-flex items-center gap-1.5 px-2.5 py-1 text-[10px] font-medium rounded bg-white text-gray-600 border border-gray-200 hover:bg-gray-50"
                  >
                    <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" />
                    </svg>
                    Edit on Eraser.io
                  </a>
                )}
              </div>
            ) : (
              <div className="text-center py-6 text-gray-400">
                <svg className="w-8 h-8 mx-auto mb-2 text-gray-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9 17V7m0 10a2 2 0 01-2 2H5a2 2 0 01-2-2V7a2 2 0 012-2h2a2 2 0 012 2m0 10a2 2 0 002 2h2a2 2 0 002-2M9 7a2 2 0 012-2h2a2 2 0 012 2m0 10V7m0 10a2 2 0 002 2h2a2 2 0 002-2V7a2 2 0 00-2-2h-2a2 2 0 00-2 2" />
                </svg>
                <p className="text-[10px]">Click Generate for professional diagram</p>
              </div>
            )}
          </div>
        </div>

        {/* Cloud Architecture Diagram Modal (desktop only) */}
        {isElectron && (
        <DiagramModal
          isOpen={diagramModal}
          onClose={() => setDiagramModal(false)}
          title={`Architecture Diagram${diagramData?.cloudProvider ? ` (${diagramData.cloudProvider.toUpperCase()})` : ''}`}
        >
          {diagramData && (
            <div className="max-w-full max-h-full">
              <CloudArchitectureDiagram
                imageUrl={diagramData.imageUrl}
                expanded={true}
                cloudProvider={diagramData.cloudProvider}
              />
            </div>
          )}
        </DiagramModal>
        )}

        {/* Pro Diagram Modal (Eraser.io) */}
        <DiagramModal
          isOpen={proDiagramModal}
          onClose={() => setProDiagramModal(false)}
          title="Pro Diagram"
        >
          {eraserDiagram && (
            <div className="max-w-full max-h-full">
              <img
                src={eraserDiagram.imageUrl}
                alt="Architecture Diagram"
                className="max-w-full max-h-[80vh] object-contain"
              />
              {eraserDiagram.editUrl && (
                <div className="mt-4 text-center">
                  <a
                    href={eraserDiagram.editUrl}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="inline-flex items-center gap-2 px-4 py-2 text-sm font-medium rounded-lg bg-gray-100 text-gray-700 border border-gray-200 hover:bg-gray-200 transition-colors"
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" />
                    </svg>
                    Edit on Eraser.io
                  </a>
                </div>
              )}
            </div>
          )}
        </DiagramModal>
      </div>
    </div>
  );
}
